import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { AdminService } from '../../../services/api';
import { ArrowLeft, Save } from 'lucide-react';
import toast from 'react-hot-toast';

export const AdminSeriesForm = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({ Series_ID: '', Title_En: '', Title_Ar: '' });
  const inputStyle = "w-full p-4 rounded-xl bg-gray-50 dark:bg-white/5 font-bold outline-none border border-transparent focus:border-primary text-xs";

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await AdminService.upsertSeries(formData);
      toast.success("Series Synchronized");
      navigate('/admin/series');
    } catch (err) { toast.error("Fault in system"); }
  };

  return (
    <div className="max-w-2xl mx-auto p-12 bg-white rounded-[3rem] shadow-sm border">
      <h2 className="text-3xl font-black uppercase italic mb-8">Forge <span className="text-primary">Series</span></h2>
      <form onSubmit={handleSubmit} className="space-y-4">
        <input placeholder="Series ID" className={inputStyle} onChange={e => setFormData({...formData, Series_ID: e.target.value})} />
        <input placeholder="Title (Eng)" className={inputStyle} onChange={e => setFormData({...formData, Title_En: e.target.value})} />
        <button className="w-full py-5 bg-black text-white rounded-2xl font-black uppercase tracking-widest text-[10px] hover:bg-primary transition-all">Commit to Series</button>
      </form>
    </div>
  );
};
